const headers = $input.first().json.headers || {};
const secret = (headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '').trim();

// Try $env first, then process.env, then fallback to known value
let expectedSecret = '';
try {
  expectedSecret = ($env.SALESHANDY_WEBHOOK_SECRET || '').trim();
} catch(e) {
  expectedSecret = 'ge-outreach-wh-2026-secure';
}

const isValid = secret === expectedSecret && secret.length > 0;

return [{
  json: {
    ...$input.first().json,
    _authValid: isValid,
    _debug_secret_match: isValid,
    _debug_secret_len: secret.length
  }
}];

const body = $input.first().json.body || $input.first().json;

const prospect = body.prospect || body.data?.prospect || body;
const reply = body.reply || body.data?.reply || body;

const email = prospect.email || body.email || '';
const firstName = prospect.firstName || prospect.first_name || body.firstName || '';
const lastName = prospect.lastName || prospect.last_name || body.lastName || '';
const company = prospect.company || body.company || '';
const replyBody = reply.body || reply.text || reply.content || body.replyBody || body.message || '';

return [{
  json: {
    email,
    firstName,
    lastName,
    company,
    replyBody
  }
}];

