const claudeResponse = $input.first().json;
const leadData = $('Extract Payload').first().json;

const validCategories = ['INTERESTED','OBJECTION','NOT_NOW','REFERRAL','WRONG_PERSON','UNSUBSCRIBE'];
let classification = '';

try {
  classification = claudeResponse.content[0].text.trim().toUpperCase();
  if (!validCategories.includes(classification)) {
    classification = 'INTERESTED'; // Safe fallback
  }
} catch (e) {
  classification = 'INTERESTED'; // Fallback if Claude fails
}

const aiFailed = !claudeResponse.content;
const replyPreview200 = (leadData.replyBody || '').substring(0, 200);
const replyPreview300 = (leadData.replyBody || '').substring(0, 300);

// Compute re-engage date (90 days from now)
const reengageDate = new Date();
reengageDate.setDate(reengageDate.getDate() + 90);
const reengageDateStr = reengageDate.toISOString().split('T')[0];

return [{
  json: {
    ...leadData,
    classification,
    aiFailed,
    replyPreview200,
    replyPreview300,
    reengageDateStr
  }
}];

